import React, { useState, useMemo } from 'react';
import { ChevronLeft, CheckCircle2, Info } from 'lucide-react';

export default function LoanApplicationScreen({
  loanType = "Business Expansion",
  onBack,
  onComplete,
  onViewTerms
}) {
  const [step, setStep] = useState(1);
  const [amount, setAmount] = useState('');
  const [plan, setPlan] = useState(12);

  const repaymentOptions = [
    { months: 12, interest: 0.05 },
    { months: 24, interest: 0.07 },
    { months: 36, interest: 0.09 },
  ];

  const selectedPlan = repaymentOptions.find(p => p.months === plan);

  const monthlyRepayment = useMemo(() => {
    if (!amount || !selectedPlan) return 0;
    const total = amount * (1 + selectedPlan.interest);
    return total / selectedPlan.months;
  }, [amount, selectedPlan]);

  return (
    <div className="flex flex-col bg-white animate-in slide-in-from-right duration-300">

      {/* Header */}
      <div className="flex items-center gap-3 px-6 py-4 sticky top-0 bg-white z-10">
        <button onClick={onBack} className="p-2 hover:bg-gray-100 rounded-full">
          <ChevronLeft className="w-6 h-6 text-gray-800" />
        </button>
        <h1 className="text-xl font-black text-gray-900">Application</h1>
      </div>

      <div className="p-6 flex-1 overflow-y-auto scrollbar-hide">

        {/* Step Indicator */}
        <div className="flex gap-2 mb-8">
          {[1, 2].map(s => (
            <div
              key={s}
              className={`h-1.5 flex-1 rounded-full ${
                s <= step ? 'bg-[#00875A]' : 'bg-gray-100'
              }`}
            />
          ))}
        </div>

        {/* STEP 1 — Loan Details */}
        {step === 1 && (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            <h2 className="text-2xl font-black mb-2">Loan Details</h2>
            <p className="text-gray-400 font-bold text-sm mb-8">
              Enter the amount and choose how long you want to repay your {loanType} loan.
            </p>

            <div className="space-y-6">

              {/* Amount */}
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">
                  Requested Amount
                </label>
                <input
                  type="number"
                  value={amount}
                  onChange={(e) => setAmount(Number(e.target.value))}
                  placeholder="0.00"
                  className="w-full p-6 bg-gray-50 rounded-[2rem] border border-gray-100 text-3xl font-black outline-none focus:border-[#00875A]"
                />
              </div>

              {/* Repayment Plan */}
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">
                  Repayment Period
                </label>
                <select
                  value={plan}
                  onChange={(e) => setPlan(Number(e.target.value))}
                  className="w-full p-5 rounded-[1.8rem] bg-gray-50 border border-gray-100 font-bold outline-none focus:border-[#00875A]"
                >
                  {repaymentOptions.map(opt => (
                    <option key={opt.months} value={opt.months}>
                      {opt.months} Months ({opt.interest * 100}% Interest)
                    </option>
                  ))}
                </select>
              </div>

              {/* Monthly Info */}
              {amount > 0 && (
                <div className="p-5 bg-emerald-50 rounded-[2rem] border border-emerald-100 flex gap-4">
                  <Info className="text-[#00875A]" size={20} />
                  <p className="text-xs text-emerald-800 font-bold">
                    Estimated monthly repayment:{" "}
                    <span className="font-black">
                      ₦{monthlyRepayment.toLocaleString(undefined, {
                        maximumFractionDigits: 2
                      })}
                    </span>
                  </p>
                </div>
              )}

              <button
                onClick={onViewTerms}
                className="text-xs font-black text-[#00875A] underline"
              >
                Read Nest Loan Terms & Conditions
              </button>
            </div>
          </div>
        )}

        {/* STEP 2 — Verification */}
        {step === 2 && (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            <h2 className="text-2xl font-black mb-2">Verification</h2>
            <p className="text-gray-400 font-bold text-sm mb-8">
              We use your Nest history to speed up approval.
            </p>

            <div className="space-y-4">
              {[
                'Identity Verified',
                'Income Verified',
                'Credit Check Passed'
              ].map((item, i) => (
                <div
                  key={i}
                  className="flex items-center justify-between p-5 border border-gray-100 rounded-[1.8rem]"
                >
                  <span className="font-black text-gray-800">{item}</span>
                  <CheckCircle2 className="text-[#00875A]" size={20} />
                </div>
              ))}
            </div>
          </div>
        )}
      </div>

      {/* Footer */}
      <div className="pb-64 border-t border-gray-50 flexflex- items-center justify-center">
        <button
          disabled={step === 1 && (!amount || amount <= 0)}
          onClick={() => step === 1 ? setStep(2) : onComplete()}
          className="w-[90%] py-5 rounded-[2rem] font-black text-white bg-[#00875A] shadow-xl disabled:opacity-50 items-center justify-center"
        >
          {step === 1 ? 'Continue' : 'Submit Application'}
        </button>
      </div>
    </div>
  );
}
